# Problem
I am trying to transfer up to 2MP images over `dlib::bridge`. I wrote a simple applications for server (the one who accepts images) and client (the one who sends images). The example works fine when i transfer relatively small images (e.g. 256x256).
However as the size of image increases the recieved image becomes only partially transfered: to bottom part if image is set to zero (see examples).
My suggestion was that the bridge object in client (sender) app dies before the transfer is completed, however, inserting a sleep after `pipe::enqueue(...)` call didn't help.
I am not sure if this a bug in `dlib::bridge` or improper use of the class.

# Code
### client.cpp:
```c++
#include <thread>
#include <string>
#include <iostream>
#include <chrono>

#include <dlib/bridge.h>
#include <dlib/array2d.h>
#include <dlib/pixel.h>
#include <dlib/image_io.h>
#include <dlib/image_transforms.h>

int main()
{
  // setting up pipe
  dlib::pipe<dlib::array2d<dlib::rgb_pixel> > out_image(1);
  dlib::bridge b_img(dlib::connect_to_ip_and_port("127.0.0.1", 3323), dlib::transmit(out_image));
  
  // generating image crops to send
  std::cout << "preparing image to send" << std::endl;
  dlib::array2d<dlib::rgb_pixel> image;
  try
  {
  dlib::load_bmp(image, "/sample_pictures/cone_scene.bmp");
  }
  catch( dlib::image_load_error & )
  {
    std::cerr << "error reading image from hard drive" << std::endl;
  }
  
  dlib::array2d<dlib::rgb_pixel> crop1;
  dlib::array2d<dlib::rgb_pixel> crop2;
  dlib::assign_image(crop1, image);
  dlib::assign_image(crop2, dlib::sub_image(image, dlib::rectangle(400, 800, 700, 1200)));

  // here we send images
  std::cout << "sending image of size (" << crop1.nc() << ", " << crop1.nr() << ") ..." << std::endl;
  out_image.enqueue(crop1);
  std::this_thread::sleep_for(std::chrono::milliseconds(5));
  // second one
  std::cout << "sending image of size (" << crop2.nc() << ", " << crop2.nr() << ") ..." << std::endl;
  out_image.enqueue(crop2);
  std::this_thread::sleep_for(std::chrono::milliseconds(5));
  return 0;
}
```

### server.cpp:
```c++
#include <thread>
#include <string>
#include <chrono>

#include <dlib/bridge.h>
#include <dlib/array2d.h>
#include <dlib/image_io.h>
#include <dlib/pixel.h>


typedef dlib::array2d<dlib::rgb_pixel> img_type;

class MessageReciever : public dlib::threaded_object
{
public:
  explicit MessageReciever(dlib::pipe<img_type> &inPipe, int max_recieved_count_ = 10)
    : in(inPipe)
    , recieved_count(0)
    , max_recieved_count(max_recieved_count_)
  {}

  void thread() override
  {
    img_type value;
    while(recieved_count < max_recieved_count)
    {
      in.dequeue(value);
      ++recieved_count;
      callback(value);      
    }
  }

  void callback(const img_type &val) const
  {
    std::cout << "rgb image recieved: (" << val.nc() << ", " << val.nr() << ")" << std::endl;
    std::ostringstream ss;
    ss << "recieved_" << std::setfill('0') << std::setw(2) << recieved_count << ".bmp";
    std::string filename = ss.str();
    std::cout << "saving to " << filename << std::endl;
    dlib::save_bmp(val, filename);
  }
private:
  dlib::pipe<img_type> &in;
  int recieved_count;
  const int max_recieved_count;
};

int main()
{
  dlib::pipe<img_type> in_img(1);
  dlib::bridge b_img(dlib::listen_on_port(3323), dlib::receive(in_img));
  
  MessageReciever img_reciever(in_img);
  img_reciever.start();
  img_reciever.wait();
  return 0;
}
```

