        {1.0f, 1.0f},
        {2.0f, 2.0f}
    };
    for (int i = 0; i < 2; ++i) {
      dataset.push_back(new Object(i, -1, sizeof(base[0]), base[i]));
    }

    Index<float>* index = MethodFactoryRegistry<float>::Instance().CreateMethod(false, "hnsw", "l2", *space, dataset);

    index->CreateIndex(AnyParams());
    cout << "Indexed dataset size: " << index->GetSize() << endl;;


    // Test Case 1. Query against new index.
    int k = 2;
    float queryVector[2] = {4.0f, 2.0f};
    KNNQuery<float> query (*space, new Object(-1, -1, sizeof(queryVector), queryVector), k);
    index->Search(&query);
    const KNNQueue<float> *result = query.Result();
    query.Print();

    // Test Case 2. Save index and query.
    string indexPath = "hnsw.index";
    index->SaveIndex(indexPath);
    KNNQuery<float> query2 (*space, new Object(-1, -1, sizeof(queryVector), queryVector), k);
    index->Search(&query2);
    query2.Print();

    // Test Case 3. Load index and query.
