    KNNQuery<float> query3 (*space, new Object(-1, -1, sizeof(queryVector), queryVector), k);
    Index<float>* index2 = MethodFactoryRegistry<float>::Instance().CreateMethod(false, "hnsw", "l2", *space, ds);
    index2->LoadIndex(indexPath);
    cout << "Reloaded dataset size: " << index2->GetSize() << endl;;
    index2->Search(&query3);
    query3.Print();
}

